class ColumnRenderer {
  private colormap: Uint8Array;
  private x: number;
  private yl: number;
  private yh: number;
  private source: Uint8Array;

  setColumn(x: number, yl: number, yh: number, colormap: Uint8Array, source: Uint8Array) {
    this.x = x;
    this.yl = yl;
    this.yh = yh;
    this.colormap = colormap;
    this.source = source;
  }

  draw() {
    for (let i = this.yl; i <= this.yh; i++) {
      screen[i * screenWidth + this.x] = this.colormap[this.source[i]];
    }
  }
}
